    25→	"github.com/unstablebuild/rune-go-sdk/cli"
    26→	"github.com/unstablebuild/rune-go-sdk/iterator"
    27→)
    28→
    29→type syntaxCLI struct {
    30→	app  *app
    31→	fs   *cli.FlagSet
    32→	cmds map[string]cli.CLI
    33→}
    34→
    35→func newSyntaxCLI(a *app) *syntaxCLI {
    36→	c := &syntaxCLI{app: a}
    37→	c.fs = cli.NewFlagSet("runectrl syntax")
    38→	c.cmds = map[string]cli.CLI{
    39→		"search":     newSyntaxSearchCLI(a),
    40→		"searchnode": newSyntaxSearchNodeCLI(a),
    41→		"query":      newSyntaxQueryCLI(a),
    42→		"querynode":  newSyntaxQueryNodeCLI(a),
    43→	}
    44→	return c
    45→}
    46→
    47→func (c *syntaxCLI) Run(
    48→	ctx context.Context, args []string,
    49→) error {
    50→	return cli.ParseAndRunCommand(
    51→		ctx, c, c.fs, c.cmds, args,
    52→	)
    53→}
    54→
    55→func (c *syntaxCLI) Man() cli.Manual {
    56→	var subMan []cli.Manual
    57→	for _, name := range []string{
    58→		"search", "searchnode", "query", "querynode",
    59→	} {
    60→		subMan = append(subMan, c.cmds[name].Man())
    61→	}
    62→	return cli.Manual{
    63→		Name:     "syntax",
    64→		Summary:  "AST-level search commands",
    65→		Synopsis: "<command>",
    66→		Commands: subMan,
    67→		Options:  *c.fs,
    68→	}
    69→}
    70→
    71→type searchResult struct {
    72→	File        string `json:"file"`
    73→	Text        string `json:"text"`
    74→	FromX       int    `json:"from_x"`
    75→	FromY       int    `json:"from_y"`
    76→	ToX         int    `json:"to_x"`
    77→	ToY         int    `json:"to_y"`
    78→	CaptureName string `json:"capture_name"`
    79→}
    80→
    81→func syntaxIterToGeneric(
    82→	sit iterator.Iterator[syntaxapi.Result],
    83→) iterator.Iterator[searchResult] {
    84→	return iterator.FromFunc(
    85→		func(ctx context.Context) (
    86→			searchResult, bool, error,
    87→		) {
    88→			r, ok := sit.Next(ctx)
    89→			if !ok {
    90→				return searchResult{}, false,
    91→					sit.Err()
    92→			}
    93→			return searchResult{
    94→				File:        fmt.Sprint(r.File),
    95→				Text:        r.Text,
    96→				FromX:       r.From.X,
    97→				FromY:       r.From.Y,
    98→				ToX:         r.To.X,
    99→				ToY:         r.To.Y,
   100→				CaptureName: r.CaptureName,
   101→			}, true, nil
   102→		},
   103→		sit.Close,
   104→	)
   105→}
   106→
   107→func printSyntaxResults(
   108→	ctx context.Context,
   109→	format string,
   110→	sit iterator.Iterator[syntaxapi.Result],
   111→) error {
   112→	defer func() { _ = sit.Close() }()
   113→	it := syntaxIterToGeneric(sit)
   114→	defer func() { _ = it.Close() }()
   115→	if format == "" {
   116→		format = "json"
   117→	}
   118→	return printIterator(ctx, format, it, []string{
   119→		"File", "Text",
   120→		"FromX", "FromY", "ToX", "ToY",
   121→		"CaptureName",
   122→	})
   123→}
   124→
   125→func parseSingleNodeType(s string) (syntaxapi.NodeCaptureName, error) {
   126→	switch s {
   127→	case "scope":
   128→		return syntaxapi.NodeCaptureScope, nil
   129→	case "namespace":
   130→		return syntaxapi.NodeCaptureDefinitionNamespace, nil
   131→	case "reference":
   132→		return syntaxapi.NodeCaptureReference, nil
   133→	case "func":
   134→		return syntaxapi.NodeCaptureDefinitionFunc, nil
   135→	case "var":
   136→		return syntaxapi.NodeCaptureDefinitionVar, nil
   137→	case "method":
   138→		return syntaxapi.NodeCaptureDefinitionMethod, nil
   139→	case "type":
   140→		return syntaxapi.NodeCaptureDefinitionType, nil
   141→	default:
   142→		return 0, fmt.Errorf(
   143→			"invalid node type %q: use "+
   144→				"scope|namespace|reference|func|var|method|type",
   145→			s,
   146→		)
   147→	}
   148→}
   149→
   150→func parseNodeType(s string) (syntaxapi.NodeCaptureName, error) {
   151→	var result syntaxapi.NodeCaptureName
   152→	for _, part := range strings.Split(s, "|") {
   153→		nodeType, err := parseSingleNodeType(part)
   154→		if err != nil {
   155→			return 0, err
   156→		}
   157→		result |= nodeType
   158→	}
   159→	return result, nil
   160→}
   161→
   162→func (a *app) pathToURI(
   163→	ctx context.Context, path string,
   164→) (workspaceapi.URI, error) {
   165→	absPath, err := filepath.Abs(path)
   166→	if err != nil {
   167→		return workspaceapi.URI{}, fmt.Errorf(
   168→			"resolve path: %w", err,
   169→		)
   170→	}
   171→	w, err := a.getWorkspace()
   172→	if err != nil {
   173→		return workspaceapi.URI{}, err
   174→	}
   175→	return w.FileSystem(ctx).URI(absPath)
   176→}
   177→
   178→type syntaxSearchCLI struct {
   179→	app      *app
   180→	fs       *cli.FlagSet
   181→	format   string
   182→	captures multiFlag
   183→}
   184→
   185→func newSyntaxSearchCLI(a *app) *syntaxSearchCLI {
   186→	c := &syntaxSearchCLI{app: a}
   187→	c.fs = cli.NewFlagSet("runectrl syntax search")
   188→	c.fs.StringVar(
   189→		&c.format, "F", "",
   190→		"Output format: table, json, or Go template",
   191→	)
   192→	c.fs.Var(
   193→		&c.captures, "c",
   194→		"Capture name filter (repeatable)",
   195→	)
   196→	return c
   197→}
   198→
   199→func (c *syntaxSearchCLI) Run(
   200→	ctx context.Context, args []string,
   201→) (retErr error) {
   202→	defer func() {
   203→		retErr = formatError(c.format, retErr)
   204→	}()
   205→	rargs, _, ok, err := cli.ParseUsage(
   206→		c, c.fs, 1, args,
   207→	)
   208→	if !ok || err != nil {
   209→		return err
   210→	}
   211→	w, err := c.app.getWorkspace()
   212→	if err != nil {
   213→		return err
   214→	}
   215→	sit, err := w.Searcher(ctx).Search(
   216→		rargs[0], []string(c.captures),
   217→	)
   218→	if err != nil {
   219→		return err
   220→	}
   221→	return printSyntaxResults(ctx, c.format, sit)
   222→}
   223→
   224→func (c *syntaxSearchCLI) Man() cli.Manual {
   225→	return cli.Manual{
   226→		Name: "search",
   227→		Summary: "Search workspace using a tree-sitter query",
   228→		Synopsis: "[options] <query>",
   229→		Options: *c.fs,
   230→	}
   231→}
   232→
   233→type syntaxSearchNodeCLI struct {
   234→	app    *app
   235→	fs     *cli.FlagSet
   236→	format string
   237→}
   238→
   239→func newSyntaxSearchNodeCLI(a *app) *syntaxSearchNodeCLI {
   240→	c := &syntaxSearchNodeCLI{app: a}
   241→	c.fs = cli.NewFlagSet("runectrl syntax searchnode")
   242→	c.fs.StringVar(
   243→		&c.format, "F", "",
   244→		"Output format: table, json, or Go template",
   245→	)
   246→	return c
   247→}
   248→
   249→func (c *syntaxSearchNodeCLI) Run(
   250→	ctx context.Context, args []string,
   251→) (retErr error) {
   252→	defer func() {
   253→		retErr = formatError(c.format, retErr)
   254→	}()
   255→	rargs, _, ok, err := cli.ParseUsage(
   256→		c, c.fs, 1, args,
   257→	)
   258→	if !ok || err != nil {
   259→		return err
   260→	}
   261→	nodeType, err := parseNodeType(rargs[0])
   262→	if err != nil {
   263→		return err
   264→	}
   265→	w, err := c.app.getWorkspace()
   266→	if err != nil {
   267→		return err
   268→	}
   269→	sit, err := w.Searcher(ctx).SearchNode(nodeType)
   270→	if err != nil {
   271→		return err
   272→	}
   273→	return printSyntaxResults(ctx, c.format, sit)
   274→}
   275→
   276→func (c *syntaxSearchNodeCLI) Man() cli.Manual {
   277→	return cli.Manual{
   278→		Name: "searchnode",
   279→		Summary: "Search workspace for known node types",
   280→		Synopsis: "[options] <node-type>\n" +
   281→			"  node-type: scope|namespace|reference|" +
   282→			"func|var|method|type",
   283→		Options: *c.fs,
   284→	}
   285→}
   286→
   287→type syntaxQueryCLI struct {
   288→	app      *app
   289→	fs       *cli.FlagSet
   290→	format   string
   291→	captures multiFlag
   292→}
   293→
   294→func newSyntaxQueryCLI(a *app) *syntaxQueryCLI {
   295→	c := &syntaxQueryCLI{app: a}
   296→	c.fs = cli.NewFlagSet("runectrl syntax query")
   297→	c.fs.StringVar(
   298→		&c.format, "F", "",
   299→		"Output format: table, json, or Go template",
   300→	)
   301→	c.fs.Var(
   302→		&c.captures, "c",
   303→		"Capture name filter (repeatable)",
   304→	)
   305→	return c
   306→}
   307→
   308→func (c *syntaxQueryCLI) Run(
   309→	ctx context.Context, args []string,
   310→) (retErr error) {
   311→	defer func() {
   312→		retErr = formatError(c.format, retErr)
   313→	}()
   314→	rargs, _, ok, err := cli.ParseUsage(
   315→		c, c.fs, 2, args,
   316→	)
   317→	if !ok || err != nil {
   318→		return err
   319→	}
   320→	uri, err := c.app.pathToURI(ctx, rargs[0])
   321→	if err != nil {
   322→		return err
   323→	}
   324→	w, err := c.app.getWorkspace()
   325→	if err != nil {
   326→		return err
   327→	}
   328→	sit, err := w.Searcher(ctx).Query(
   329→		uri, rargs[1], []string(c.captures),
   330→	)
   331→	if err != nil {
   332→		return err
   333→	}
   334→	return printSyntaxResults(ctx, c.format, sit)
   335→}
