   366→		retErr = formatError(c.format, retErr)
   367→	}()
   368→	rargs, _, ok, err := cli.ParseUsage(
   369→		c, c.fs, 2, args,
   370→	)
   371→	if !ok || err != nil {
   372→		return err
   373→	}
   374→	uri, err := c.app.pathToURI(ctx, rargs[0])
   375→	if err != nil {
   376→		return err
   377→	}
   378→	nodeType, err := parseNodeType(rargs[1])
   379→	if err != nil {
   380→		return err
