    28→
    29→// windowID implements browserapi.Window.
    30→type windowID uint64
    31→
    32→func (w windowID) WindowID() uint64 { return uint64(w) }
    33→
    34→func resolveHandler(
    35→	ctx context.Context,
    36→	a *app,
    37→	uri string,
    38→) (browserapi.Handler, error) {
    39→	w, err := a.getWorkspace()
    40→	if err != nil {
    41→		return nil, err
    42→	}
    43→	parsed, err := workspaceapi.ParseURI(uri)
    44→	if err != nil {
    45→		return nil, err
    46→	}
    47→	return w.ResourceOpener(ctx).Open(parsed)
    48→}
    49→
    50→func parseWindowID(s string) (windowID, error) {
    51→	v, err := strconv.ParseUint(s, 10, 64)
    52→	if err != nil {
    53→		return 0, fmt.Errorf(
    54→			"invalid window ID %q: %w", s, err,
    55→		)
    56→	}
    57→	return windowID(v), nil
    58→}
    59→
    60→func parseOrientation(
    61→	s string,
    62→) (browserapi.Orientation, error) {
    63→	switch s {
    64→	case "default":
    65→		return browserapi.OrientationDefault, nil
    66→	case "top":
    67→		return browserapi.OrientationTop, nil
    68→	case "bottom":
    69→		return browserapi.OrientationBottom, nil
    70→	case "left":
    71→		return browserapi.OrientationLeft, nil
    72→	case "right":
    73→		return browserapi.OrientationRight, nil
    74→	default:
    75→		return 0, fmt.Errorf(
    76→			"invalid orientation %q:"+
    77→				" use default|top|bottom|left|right", s,
    78→		)
    79→	}
    80→}
    81→
    82→type wmCLI struct {
    83→	app  *app
    84→	fs   *cli.FlagSet
    85→	cmds map[string]cli.CLI
    86→}
    87→
    88→func newWMCLI(a *app) *wmCLI {
    89→	c := &wmCLI{app: a}
    90→	c.fs = cli.NewFlagSet("runectrl wm")
    91→	c.cmds = map[string]cli.CLI{
    92→		"focus":       newWMFocusCLI(a),
    93→		"split":       newWMSplitCLI(a),
    94→		"floating":    newWMFloatingCLI(a),
    95→		"set-content": newWMSetContentCLI(a),
    96→		"close":       newWMCloseCLI(a),
    97→	}
    98→	return c
    99→}
   100→
   101→func (c *wmCLI) Run(
   102→	ctx context.Context, args []string,
   103→) error {
   104→	return cli.ParseAndRunCommand(
   105→		ctx, c, c.fs, c.cmds, args,
   106→	)
   107→}
   108→
   109→func (c *wmCLI) Man() cli.Manual {
   110→	var subMan []cli.Manual
   111→	for _, name := range []string{
   112→		"focus", "split", "floating",
   113→		"set-content", "close",
   114→	} {
   115→		subMan = append(subMan, c.cmds[name].Man())
   116→	}
   117→	return cli.Manual{
   118→		Name:     "wm",
   119→		Summary:  "Window manager commands",
   120→		Synopsis: "<command>",
   121→		Commands: subMan,
   122→		Options:  *c.fs,
   123→	}
   124→}
   125→
   126→type wmFocusCLI struct {
   127→	app    *app
   128→	fs     *cli.FlagSet
   129→	format string
   130→}
   131→
   132→func newWMFocusCLI(a *app) *wmFocusCLI {
   133→	c := &wmFocusCLI{app: a}
   134→	c.fs = cli.NewFlagSet("runectrl wm focus")
   135→	c.fs.StringVar(
   136→		&c.format, "F", "",
   137→		"Output format: table, json, or Go template",
   138→	)
   139→	return c
   140→}
   141→
   142→func (c *wmFocusCLI) Run(
   143→	ctx context.Context, args []string,
   144→) (retErr error) {
   145→	defer func() {
   146→		retErr = formatError(c.format, retErr)
   147→	}()
   148→	_, _, ok, err := cli.ParseUsage(c, c.fs, 0, args)
   149→	if !ok || err != nil {
   150→		return err
   151→	}
   152→	w, err := c.app.getWorkspace()
   153→	if err != nil {
   154→		return err
   155→	}
   156→	win, err := w.WindowManager(ctx).Focus()
   157→	if err != nil {
   158→		return err
   159→	}
   160→	return printResult(
   161→		ctx, c.format, win.WindowID(),
   162→		func(v uint64) { fmt.Println(v) },
   163→		[]string{"WindowID"},
   164→	)
   165→}
   166→
   167→func (c *wmFocusCLI) Man() cli.Manual {
   168→	return cli.Manual{
   169→		Name:     "focus",
   170→		Summary:  "Get the focused window ID",
   171→		Synopsis: "[options]",
   172→		Options:  *c.fs,
   173→	}
   174→}
   175→
   176→type wmSplitCLI struct {
   177→	app         *app
   178→	fs          *cli.FlagSet
   179→	format      string
   180→	orientation string
   181→}
   182→
   183→func newWMSplitCLI(a *app) *wmSplitCLI {
   184→	c := &wmSplitCLI{app: a}
   185→	c.fs = cli.NewFlagSet("runectrl wm split")
   186→	c.fs.StringVar(
   187→		&c.format, "F", "",
   188→		"Output format: table, json, or Go template",
   189→	)
   190→	c.fs.StringVar(
   191→		&c.orientation, "o", "default",
   192→		"Orientation: default|top|bottom|left|right",
   193→	)
   194→	return c
   195→}
   196→
   197→func (c *wmSplitCLI) Run(
   198→	ctx context.Context, args []string,
   199→) (retErr error) {
   200→	defer func() {
   201→		retErr = formatError(c.format, retErr)
   202→	}()
   203→	rargs, _, ok, err := cli.ParseUsage(
   204→		c, c.fs, 2, args,
   205→	)
   206→	if !ok || err != nil {
   207→		return err
   208→	}
   209→	orient, err := parseOrientation(c.orientation)
   210→	if err != nil {
   211→		return err
   212→	}
   213→	wid, err := parseWindowID(rargs[0])
   214→	if err != nil {
   215→		return err
   216→	}
   217→	h, err := resolveHandler(ctx, c.app, rargs[1])
   218→	if err != nil {
   219→		return err
   220→	}
   221→	w, err := c.app.getWorkspace()
   222→	if err != nil {
   223→		return err
   224→	}
   225→	win, err := w.WindowManager(ctx).Split(
   226→		orient, wid, h,
   227→	)
   228→	if err != nil {
   229→		return err
   230→	}
   231→	return printResult(
   232→		ctx, c.format, win.WindowID(),
   233→		func(v uint64) { fmt.Println(v) },
   234→		[]string{"WindowID"},
   235→	)
   236→}
   237→
   238→func (c *wmSplitCLI) Man() cli.Manual {
   239→	return cli.Manual{
   240→		Name: "split",
   241→		Summary: "Split a window",
   242→		Synopsis: "[options] <window-id>" +
   243→			" <handler-uri>",
   244→		Options: *c.fs,
   245→	}
   246→}
   247→
   248→type wmFloatingCLI struct {
   249→	app     *app
   250→	fs      *cli.FlagSet
   251→	format  string
   252→	align   string
   253→	offsetX int
   254→	offsetY int
   255→}
   256→
   257→func newWMFloatingCLI(a *app) *wmFloatingCLI {
   258→	c := &wmFloatingCLI{app: a}
   259→	c.fs = cli.NewFlagSet("runectrl wm floating")
   260→	c.fs.StringVar(
   261→		&c.format, "F", "",
   262→		"Output format: table, json, or Go template",
   263→	)
   264→	c.fs.StringVar(
   265→		&c.align, "a", "",
   266→		"Alignment: default|left|right|"+
   267→			"top|bottom|centered",
   268→	)
   269→	c.fs.IntVar(&c.offsetX, "x", 0, "X offset")
   270→	c.fs.IntVar(&c.offsetY, "y", 0, "Y offset")
   271→	return c
   272→}
   273→
   274→func (c *wmFloatingCLI) Run(
   275→	ctx context.Context, args []string,
   276→) (retErr error) {
   277→	defer func() {
   278→		retErr = formatError(c.format, retErr)
   279→	}()
   280→	rargs, _, ok, err := cli.ParseUsage(
   281→		c, c.fs, 1, args,
   282→	)
   283→	if !ok || err != nil {
   284→		return err
   285→	}
   286→	h, err := resolveHandler(ctx, c.app, rargs[0])
   287→	if err != nil {
   288→		return err
   289→	}
   290→	fh, ok := h.(browserapi.Floating)
   291→	if !ok {
   292→		return fmt.Errorf(
   293→			"handler does not implement Floating",
   294→		)
   295→	}
   296→	alignment, err := parseAlignment(c.align)
   297→	if err != nil {
   298→		return err
   299→	}
   300→	cfg := browserapi.FloatingConfig{
   301→		Alignment: alignment,
   302→		Offset: term.Coordinates{
   303→			X: c.offsetX, Y: c.offsetY,
   304→		},
   305→	}
   306→	w, err := c.app.getWorkspace()
   307→	if err != nil {
   308→		return err
   309→	}
   310→	win, err := w.WindowManager(ctx).Floating(fh, cfg)
   311→	if err != nil {
   312→		return err
   313→	}
   314→	return printResult(
   315→		ctx, c.format, win.WindowID(),
   316→		func(v uint64) { fmt.Println(v) },
   317→		[]string{"WindowID"},
   318→	)
   319→}
   320→
   321→func (c *wmFloatingCLI) Man() cli.Manual {
   322→	return cli.Manual{
   323→		Name:     "floating",
   324→		Summary:  "Create a floating window",
   325→		Synopsis: "[options] <handler-uri>",
   326→		Options:  *c.fs,
   327→	}
   328→}
   329→
