package main

import (
	"context"
	"fmt"
	"strconv"
	"strings"

	"github.com/unstablebuild/rune-go-sdk/api/semanticapi"
	"github.com/unstablebuild/rune-go-sdk/cli"
	"github.com/unstablebuild/rune-go-sdk/iterator"
)

type lspCLI struct {
	app  *app
	fs   *cli.FlagSet
	cmds map[string]cli.CLI
}

func newLSPCLI(a *app) *lspCLI {
	c := &lspCLI{app: a}
	c.fs = cli.NewFlagSet("runectrl lsp")
	c.cmds = map[string]cli.CLI{
		"hover":             newLSPHoverCLI(a),
		"definition":        newLSPDefinitionCLI(a),
		"references":        newLSPReferencesCLI(a),
		"symbols":           newLSPSymbolsCLI(a),
		"workspace-symbols": newLSPWorkspaceSymbolsCLI(a),
		"diagnostics":       newLSPDiagnosticsCLI(a),
		"rename":            newLSPRenameCLI(a),
		"code-actions":      newLSPCodeActionsCLI(a),
	}
	return c
}

func (c *lspCLI) Run(
	ctx context.Context, args []string,
) error {
	return cli.ParseAndRunCommand(
		ctx, c, c.fs, c.cmds, args,
	)
}

func (c *lspCLI) Man() cli.Manual {
	var subMan []cli.Manual
	for _, name := range []string{
		"hover", "definition", "references",
		"symbols", "workspace-symbols",
		"diagnostics", "rename", "code-actions",
	} {
		subMan = append(subMan, c.cmds[name].Man())
	}
	return cli.Manual{
		Name:     "lsp",
		Summary:  "Language Server Protocol commands",
		Synopsis: "<command>",
		Commands: subMan,
		Options:  *c.fs,
	}
}

// parsePosition parses line and col strings as uint32.
func parsePosition(
	lineStr, colStr string,
) (semanticapi.Position, error) {
	line, err := strconv.ParseUint(lineStr, 10, 32)
	if err != nil {
		return semanticapi.Position{}, fmt.Errorf(
			"invalid line %q: %w", lineStr, err,
		)
	}
	col, err := strconv.ParseUint(colStr, 10, 32)
	if err != nil {
		return semanticapi.Position{}, fmt.Errorf(
			"invalid column %q: %w", colStr, err,
		)
	}
	return semanticapi.Position{
		Line:      uint32(line),
		Character: uint32(col),
	}, nil
}

func (a *app) getLSP(
	ctx context.Context,
) (semanticapi.LSP, error) {
	w, err := a.getWorkspace()
	if err != nil {
		return nil, err
	}
	return w.LSP(ctx), nil
}

type flatLocation struct {
	URI       string `json:"uri"`
	StartLine uint32 `json:"start_line"`
	StartChar uint32 `json:"start_char"`
	EndLine   uint32 `json:"end_line"`
	EndChar   uint32 `json:"end_char"`
}

func toFlatLocations(
	locs []semanticapi.Location,
) []flatLocation {
	out := make([]flatLocation, len(locs))
	for i, l := range locs {
		out[i] = flatLocation{
			URI:       l.URI,
			StartLine: l.Range.Start.Line,
			StartChar: l.Range.Start.Character,
			EndLine:   l.Range.End.Line,
			EndChar:   l.Range.End.Character,
		}
	}
	return out
}

func printLocations(
	ctx context.Context,
	format string,
	locs []semanticapi.Location,
) error {
	flat := toFlatLocations(locs)
	if format == "" {
		for _, f := range flat {
			fmt.Printf(
				"%s %d:%d-%d:%d\n",
				f.URI,
				f.StartLine, f.StartChar,
				f.EndLine, f.EndChar,
			)
		}
		return nil
	}
	it := iterator.FromSlice(flat)
	return printIterator(ctx, format, it, []string{
		"URI", "StartLine", "StartChar",
		"EndLine", "EndChar",
	})
}

func symbolKindString(k semanticapi.SymbolKind) string {
	switch k {
	case semanticapi.SymbolKindFile:
		return "File"
	case semanticapi.SymbolKindModule:
		return "Module"
	case semanticapi.SymbolKindNamespace:
		return "Namespace"
	case semanticapi.SymbolKindPackage:
		return "Package"
	case semanticapi.SymbolKindClass:
		return "Class"
	case semanticapi.SymbolKindMethod:
		return "Method"
	case semanticapi.SymbolKindProperty:
		return "Property"
	case semanticapi.SymbolKindField:
		return "Field"
	case semanticapi.SymbolKindConstructor:
		return "Constructor"
	case semanticapi.SymbolKindEnum:
		return "Enum"
	case semanticapi.SymbolKindInterface:
		return "Interface"
	case semanticapi.SymbolKindFunction:
		return "Function"
	case semanticapi.SymbolKindVariable:
		return "Variable"
	case semanticapi.SymbolKindConstant:
		return "Constant"
	case semanticapi.SymbolKindString:
		return "String"
	case semanticapi.SymbolKindNumber:
		return "Number"
	case semanticapi.SymbolKindBoolean:
		return "Boolean"
	case semanticapi.SymbolKindArray:
		return "Array"
	case semanticapi.SymbolKindObject:
		return "Object"
	case semanticapi.SymbolKindKey:
		return "Key"
	case semanticapi.SymbolKindNull:
		return "Null"
	case semanticapi.SymbolKindEnumMember:
		return "EnumMember"
	case semanticapi.SymbolKindStruct:
		return "Struct"
	case semanticapi.SymbolKindEvent:
		return "Event"
	case semanticapi.SymbolKindOperator:
		return "Operator"
	case semanticapi.SymbolKindTypeParameter:
		return "TypeParameter"
	default:
		return fmt.Sprintf("Unknown(%d)", k)
	}
}

func severityString(
	s semanticapi.DiagnosticSeverity,
) string {
	switch s {
	case semanticapi.DiagnosticSeverityError:
		return "Error"
	case semanticapi.DiagnosticSeverityWarning:
		return "Warning"
	case semanticapi.DiagnosticSeverityInformation:
		return "Information"
	case semanticapi.DiagnosticSeverityHint:
		return "Hint"
	default:
		return fmt.Sprintf("Unknown(%d)", s)
	}
}

// --- hover ---

type lspHoverCLI struct {
	app    *app
	fs     *cli.FlagSet
	format string
}

func newLSPHoverCLI(a *app) *lspHoverCLI {
	c := &lspHoverCLI{app: a}
	c.fs = cli.NewFlagSet("runectrl lsp hover")
	c.fs.StringVar(
		&c.format, "F", "",
		"Output format: table, json, or Go template",
	)
	return c
}

func (c *lspHoverCLI) Run(
	ctx context.Context, args []string,
) (retErr error) {
	defer func() {
		retErr = formatError(c.format, retErr)
	}()
	rargs, _, ok, err := cli.ParseUsage(
		c, c.fs, 3, args,
	)
	if !ok || err != nil {
		return err
	}
	uri, err := c.app.pathToURI(ctx, rargs[0])
	if err != nil {
		return err
	}
	pos, err := parsePosition(rargs[1], rargs[2])
	if err != nil {
		return err
	}
	lsp, err := c.app.getLSP(ctx)
	if err != nil {
		return err
	}
	h, err := lsp.Hover(ctx, semanticapi.HoverParams{
		TextDocument: semanticapi.TextDocumentIdentifier{
			URI: uri.String(),
		},
		Position: pos,
	})
	if err != nil {
		return err
	}
	if h == nil {
		return printString(c.format, "", []string{
			"Contents",
		})
	}
	type hoverResult struct {
		Contents string `json:"contents"`
		Kind     string `json:"kind"`
	}
	r := hoverResult{
		Contents: h.Contents.Value,
		Kind:     string(h.Contents.Kind),
	}
	return printResult(
		ctx, c.format, r,
		func(v hoverResult) {
			fmt.Println(v.Contents)
		},
		[]string{"Contents", "Kind"},
	)
}

func (c *lspHoverCLI) Man() cli.Manual {
	return cli.Manual{
		Name:    "hover",
		Summary: "Get hover info at a position",
		Synopsis: "[options] <file>" +
			" <line> <col>",
		Options: *c.fs,
	}
}

// --- definition ---

type lspDefinitionCLI struct {
	app    *app
	fs     *cli.FlagSet
	format string
}

func newLSPDefinitionCLI(a *app) *lspDefinitionCLI {
	c := &lspDefinitionCLI{app: a}
	c.fs = cli.NewFlagSet("runectrl lsp definition")
	c.fs.StringVar(
		&c.format, "F", "",
		"Output format: table, json, or Go template",
	)
	return c
}

func (c *lspDefinitionCLI) Run(
	ctx context.Context, args []string,
) (retErr error) {
	defer func() {
		retErr = formatError(c.format, retErr)
	}()
	rargs, _, ok, err := cli.ParseUsage(
		c, c.fs, 3, args,
	)
	if !ok || err != nil {
		return err
	}
	uri, err := c.app.pathToURI(ctx, rargs[0])
	if err != nil {
		return err
	}
	pos, err := parsePosition(rargs[1], rargs[2])
	if err != nil {
		return err
	}
	lsp, err := c.app.getLSP(ctx)
	if err != nil {
		return err
	}
	locs, err := lsp.Definition(
		ctx, semanticapi.DefinitionParams{
			TextDocument: semanticapi.TextDocumentIdentifier{
				URI: uri.String(),
