	defer func() {
		retErr = formatError(c.format, retErr)
	}()
	rargs, _, ok, err := cli.ParseUsage(
		c, c.fs, 4, args,
	)
	if !ok || err != nil {
		return err
	}
	uri, err := c.app.pathToURI(ctx, rargs[0])
	if err != nil {
		return err
	}
	pos, err := parsePosition(rargs[1], rargs[2])
	if err != nil {
		return err
	}
	newName := rargs[3]
	lsp, err := c.app.getLSP(ctx)
	if err != nil {
		return err
	}
	edit, err := lsp.Rename(
		ctx, semanticapi.RenameParams{
			TextDocument: semanticapi.TextDocumentIdentifier{
				URI: uri.String(),
			},
			Position: pos,
			NewName:  newName,
		},
	)
	if err != nil {
		return err
	}
	if edit == nil {
		return printString(
			c.format, "no edits",
			[]string{"Result"},
		)
	}
	var flat []flatRenameEdit
	for u, edits := range edit.Changes {
		flat = append(flat, flatRenameEdit{
			URI:   u,
			Edits: len(edits),
		})
	}
	if c.format == "" {
		for _, f := range flat {
			fmt.Printf("%s: %d edits\n", f.URI, f.Edits)
		}
		return nil
	}
	it := iterator.FromSlice(flat)
	return printIterator(ctx, c.format, it, []string{
		"URI", "Edits",
	})
