				require.Contains(t, out, `"success":true`)
			},
		},
		{
			name:   "t",
			format: "table",
			check: func(t *testing.T, out string) {
				require.Contains(t, out, "DATA DIR")
			},
		},
		{
			name:   "g",
			format: "{{.DataDir}}",
			check: func(t *testing.T, out string) {
				require.NotEmpty(t, out)
			},
		},
	}
	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			env := newTestEnv(t)
			defer env.cleanup()
			out, err := env.run(
				"datadir", "-F", tt.format,
			)
			require.NoError(t, err)
			tt.check(t, out)
		})
	}
}

