   165→	if err != nil {
   166→		path = orig
   167→	}
   168→	if path == "~" || path == "/~" {
   169→		usr, err := getUser()
   170→		if err != nil {
   171→			return "", fmt.Errorf("could not get current user: %s", err)
   172→		}
   173→		path = usr.HomeDir
   174→	} else if strings.HasPrefix(path, "~/") {
   175→		usr, err := getUser()
   176→		if err != nil {
   177→			return "", fmt.Errorf("could not get current user: %s", err)
   178→		}
   179→		path = filepath.Join(usr.HomeDir, path[2:])
   180→	} else if strings.HasPrefix(path, "/~/") {
   181→		usr, err := getUser()
   182→		if err != nil {
   183→			return "", fmt.Errorf("could not get current user: %s", err)
   184→		}
   185→		path = filepath.Join(usr.HomeDir, path[3:])
   186→	}
   187→	if filepath.IsAbs(path) {
   188→		return path, nil
   189→	}
   190→	cwd, err := cwdFn()
   191→	if err != nil {
   192→		return "", fmt.Errorf("could not get cwd: %s", err)
   193→	}
   194→	abs := filepath.Join(cwd, path)
   195→	return abs, nil
   196→}
   197→
   198→// HasPrefix returns tests whether uri begins with prefix.
   199→func HasPrefix(uri, prefix URI) bool {
   200→	return uri.Scheme() == prefix.Scheme() &&
   201→		uri.Hostname() == prefix.Hostname() &&
   202→		uri.Port() == prefix.Port() &&
   203→		uri.User() == prefix.User() &&
   204→		strings.HasPrefix(uri.Path(), prefix.Path())
   205→}
   206→
   207→// RelPath returns target's path as a relative path of base,
   208→// or if that's not possible, it will return target's Path
   209→// without change.
   210→func RelPath(base, target URI) string {
   211→	if HasPrefix(target, base) {
   212→		relpath, err := filepath.Rel(base.Path(), target.Path())
   213→		if err == nil {
   214→			return relpath
   215→		}
   216→	}
   217→	return target.Path()
   218→}
   219→
   220→// CurrentUserHostURI builds a URI from a path. If path is relative
   221→// it uses the current working directory as the base of the path and
   222→// if ~ is used to identify the home directory, the current user's home
   223→// directory is used as the base.
   224→// This should only used instead of Manager.URI before a workspace.Manager is
   225→// constructed or for other advanced uses cases.
   226→func CurrentUserHostURI(path string) (URI, error) {
   227→	absPath, err := ExpandPath(path, user.Current, os.Getwd)
   228→	if err != nil {
   229→		return URI{}, err
   230→	}
   231→	return makeLocalURI(absPath)
   232→}
   233→
   234→// WithPath maps the given URI to returns a URI with
   235→// the same components but path set to path.
   236→func WithPath(u URI, path string) (URI, error) {
   237→	u.parsed.Path = path
   238→	return uriFromURL(&u.parsed)
   239→}
   240→
   241→// RandomURI generates a random URI with the given scheme.
   242→//
   243→// Under the hood it uses math.Rand so clients can manage
   244→// seeding the default rand.Source, if desired.
   245→func RandomURI(scheme string) URI {
   246→	ret, err := ParseURI(fmt.Sprintf("%s:///%d", scheme, rand.Int()))
   247→	if err != nil {
   248→		// this panic indicates a programmer error
   249→		// above when crafting URI
   250→		panic(err)
   251→	}
   252→	return ret
   253→}
   254→
   255→func uriFromURL(u *url.URL) (URI, error) {
   256→	if u.Host != "" {
   257→		return makeRemoteURI(u), nil
   258→	}
   259→	return makeFileURI(u)
   260→}
   261→
   262→func makeRemoteURI(u *url.URL) URI {
   263→	if u.Path == "" {
   264→		u.Path = "/"
   265→	}
   266→	name := fmt.Sprintf("%s://%s%s", u.Scheme, u.Host, path.Join("/", u.Path))
   267→	return URI{uri: u.String(), parsed: *u, name: name}
   268→}
   269→
   270→func makeFileURI(u *url.URL) (URI, error) {
   271→	path := sanitizeFilePath(u.Path)
   272→	u.Path = path
   273→	if u.Scheme == "" {
   274→		return URI{}, fmt.Errorf("invalid empty scheme %#v", u)
   275→	}
   276→	return URI{uri: u.String(), parsed: *u, name: filepath.Base(path)}, nil
   277→}
   278→
   279→func makeLocalURI(path string) (URI, error) {
   280→	uriStr := "file://" + path
   281→	u, err := url.Parse(uriStr)
   282→	if err != nil {
   283→		return URI{}, err
   284→	}
   285→
   286→	return makeFileURI(u)
   287→}
   288→
   289→func sanitizeFilePath(resource string) string {
   290→	resource = filepath.Clean(resource)
   291→	return sanitizeLine(resource)
   292→}
   293→
   294→func sanitizeLine(in string) string {
   295→	var b strings.Builder
   296→	for _, r := range in {
   297→		switch r {
   298→		case '\x00':
   299→		case '\n':
   300→		default:
   301→			b.WriteRune(r)
   302→		}
   303→	}
   304→	return b.String()
   305→}
