    15→package iterator
    16→
    17→import (
    18→	"context"
    19→
    20→	"github.com/ernestrc/go-multierror"
    21→)
    22→
    23→// ToSlice consumes the given iterator and returns a slice with
    24→// all of the elements produced.
    25→func ToSlice[T any](ctx context.Context, it Iterator[T]) ([]T, error) {
    26→	ret := make([]T, 0)
    27→	for {
    28→		t, ok := it.Next(ctx)
    29→		if !ok {
    30→			if err := it.Err(); err != nil {
    31→				return nil, err
    32→			}
    33→			return ret, nil
    34→		}
    35→		ret = append(ret, t)
    36→	}
    37→}
    38→
    39→// FromSlice returns an iterator backed by the given slice of elements.
    40→func FromSlice[T any](els []T) Iterator[T] {
    41→	return &sliceIter[T]{els: els}
    42→}
    43→
    44→// FromFunc returns an Iterator backed by the provided function.
    45→func FromFunc[T any](
    46→	fn func(context.Context) (T, bool, error),
    47→	close func() error,
    48→) Iterator[T] {
    49→	return &fnIter[T]{fn: fn, close: close}
    50→}
    51→
    52→// IsEmpty consumes the first element in i and returns true if it is empty
    53→// or false if not and returns a new iterator that should be used instead of i.
    54→//
    55→// The given iterator is consumed in either case, so its Close method
    56→// is wrapped with the returned iterator, or if the given iterator is empty,
    57→// its Close method is called for the caller, so it's safe to override the variable
    58→// holding the passed iterator with the return value of this function.
    59→func IsEmpty[T any](ctx context.Context, i Iterator[T]) (Iterator[T], bool) {
    60→	el, ok := i.Next(ctx)
    61→	if !ok {
    62→		_ = i.Close()
    63→		return FromSlice[T](nil), true
    64→	}
    65→
    66→	return FromFunc(func(ctx context.Context) (T, bool, error) {
    67→		if ok {
    68→			ok = false
    69→			return el, true, nil
    70→		}
    71→		iEl, iOk := i.Next(ctx)
    72→		if !iOk {
    73→			return iEl, false, i.Err()
    74→		}
    75→		return iEl, iOk, nil
    76→	}, i.Close), false
    77→}
    78→
    79→type fnIter[T any] struct {
    80→	err   error
    81→	fn    func(context.Context) (T, bool, error)
    82→	close func() error
    83→}
    84→
    85→func (f *fnIter[T]) Next(ctx context.Context) (T, bool) {
    86→	t, ok, err := f.fn(ctx)
    87→	if err != nil {
    88→		f.err = multierror.Append(f.err, err)
    89→		return t, false
    90→	}
    91→	return t, ok
    92→}
    93→
    94→func (f *fnIter[T]) Err() error {
    95→	return f.err
    96→}
    97→
    98→func (f *fnIter[T]) Close() error {
    99→	return f.close()
   100→}
   101→
   102→type sliceIter[T any] struct {
   103→	els []T
   104→}
   105→
   106→func (i *sliceIter[T]) Next(context.Context) (ret T, ok bool) {
   107→	if len(i.els) == 0 {
   108→		return
   109→	}
   110→	ok = true
   111→	ret = i.els[0]
   112→	i.els = i.els[1:]
   113→	return
   114→}
   115→
   116→func (i *sliceIter[T]) Err() error {
   117→	return nil
   118→}
   119→
   120→func (i *sliceIter[T]) Close() error {
   121→	return nil
   122→}
