   217→
   218→func completionItemToProto(c semanticapi.CompletionItem) *CompletionItem {
   219→	ret := &CompletionItem{
   220→		Label:               c.Label,
   221→		Kind:                int32(c.Kind),
   222→		Detail:              c.Detail,
   223→		Documentation:       markupContentPtrToProto(c.Documentation),
   224→		InsertText:          c.InsertText,
   225→		InsertTextFormat:    int32(c.InsertTextFormat),
   226→		DocumentationString: c.DocumentationString,
   227→	}
   228→	if c.TextEdit != nil {
   229→		ret.TextEdit = textEditToProto(*c.TextEdit)
   230→	}
   231→	if len(c.Tags) > 0 {
   232→		tags := make([]int32, len(c.Tags))
   233→		for i, t := range c.Tags {
   234→			tags[i] = int32(t)
   235→		}
   236→		ret.Tags = tags
   237→	}
   238→	return ret
   239→}
   240→
   241→func completionItemFromProto(c *CompletionItem) semanticapi.CompletionItem {
   242→	if c == nil {
   243→		return semanticapi.CompletionItem{}
   244→	}
   245→	ret := semanticapi.CompletionItem{
   246→		Label:               c.Label,
   247→		Kind:                semanticapi.CompletionItemKind(c.Kind),
   248→		Detail:              c.Detail,
   249→		Documentation:       markupContentPtrFromProto(c.Documentation),
   250→		InsertText:          c.InsertText,
   251→		InsertTextFormat:    semanticapi.InsertTextFormat(c.InsertTextFormat),
   252→		DocumentationString: c.DocumentationString,
   253→	}
   254→	if c.TextEdit != nil {
   255→		te := textEditFromProto(c.TextEdit)
   256→		ret.TextEdit = &te
   257→	}
   258→	if len(c.Tags) > 0 {
   259→		tags := make([]semanticapi.CompletionItemTag, len(c.Tags))
   260→		for i, t := range c.Tags {
   261→			tags[i] = semanticapi.CompletionItemTag(t)
