    28→// UpdateUpdatedAtField updates the default UpdatedAt field in the given document.
    29→// Deprecated: Use UpdateDefaultUpdatedAtField.
    30→func UpdateUpdatedAtField(marshaler docmarshal.Marshaler, doc any) any {
    31→	now := time.Now()
    32→	return UpdateDefaultUpdatedAtField(doc, now, marshaler.DefaultLowerCase())
    33→}
    34→
    35→// UpdateDefaultUpdatedAtField updates the default UpdatedAt field in the given document.
    36→// If lowerCase is false DefaultUpdatedAtField is used, otherwise LowerUpdatedAtField is used.
    37→// If doc is not a map, a struct or a pointer to a struct, this method panics.
    38→func UpdateDefaultUpdatedAtField(doc any, now time.Time, lowerCase bool) any {
    39→	updatedAtField := storageapi.DefaultUpdatedAtField
    40→	if lowerCase {
    41→		updatedAtField = storageapi.LowerUpdatedAtField
    42→	}
    43→	m, ok := doc.(map[string]any)
    44→	if ok {
    45→		doc = setMapField(m, updatedAtField, now)
    46→	} else if reflect.ValueOf(doc).Kind() == reflect.Struct {
    47→		dst := cloneReflectValue(doc)
    48→		reflectSetTimeField(dst, updatedAtField, now)
    49→		doc = dst.Interface()
    50→	} else {
    51→		dst := reflect.ValueOf(doc)
    52→		reflectSetTimeField(dst, updatedAtField, now)
    53→		doc = dst.Interface()
    54→	}
    55→	return doc
    56→}
