    59→// Deprecated: Use UpdateDefaultCreatedAtField.
    60→func UpdateCreatedAtField(marshaler docmarshal.Marshaler, doc any) any {
    61→	now := time.Now()
    62→	return UpdateDefaultCreatedAtField(doc, now, marshaler.DefaultLowerCase())
    63→}
