    65→// DerefUpdateValue dereferences data until it finds a value that can be used
    66→// by UpdateDefaultCreatedAtField and UpdateDefaultUpdatedAtField to update
    67→// their updated at or created at fields.
    68→func DerefUpdateValue(data reflect.Value) (any, error) {
    69→	prev := data
    70→	for {
    71→		switch data.Kind() {
    72→		case reflect.Struct:
    73→			if prev.Kind() == reflect.Ptr {
    74→				return prev.Interface(), nil
    75→			}
    76→			return nil, errors.New("only pointers to a struct or map values are allowed")
    77→		case reflect.Map:
    78→			return data.Interface(), nil
    79→		case reflect.Ptr:
    80→			prev = data
    81→			data = data.Elem()
    82→		case reflect.Interface:
    83→			if data.NumMethod() == 0 {
    84→				prev = data
    85→				data = data.Elem()
    86→				continue
    87→			}
    88→			fallthrough
    89→		default:
    90→			return nil, errors.New("only pointers to a struct or map values are allowed")
    91→		}
    92→	}
    93→}
    94→
    95→// UpdateDefaultCreatedAtField updates the default CreatedAt field in the given document
    96→// and the default UpdatedAt field.
    97→// If lowerCase is false DefaultUpdatedAtField is used, otherwise LowerUpdatedAtField is used.
    98→// If doc is not a map, a struct or a pointer to a struct, this method panics.
    99→func UpdateDefaultCreatedAtField(doc any, now time.Time, lowerCase bool) any {
   100→	updatedAtField := storageapi.DefaultUpdatedAtField
   101→	createdAtField := storageapi.DefaultCreatedAtField
   102→	m, ok := doc.(map[string]any)
   103→	if lowerCase {
   104→		updatedAtField = storageapi.LowerUpdatedAtField
   105→		createdAtField = storageapi.LowerCreatedAtField
   106→	}
   107→	if ok {
   108→		setMapField(m, updatedAtField, now)
   109→		setMapField(m, createdAtField, now)
   110→	} else if reflect.ValueOf(doc).Kind() == reflect.Struct {
   111→		dst := cloneReflectValue(doc)
   112→		now := time.Now()
   113→		reflectSetTimeField(dst, storageapi.DefaultCreatedAtField, now)
   114→		reflectSetTimeField(dst, storageapi.DefaultUpdatedAtField, now)
   115→		doc = dst.Elem().Interface()
   116→	} else {
   117→		dst := reflect.ValueOf(doc)
   118→		now := time.Now()
   119→		reflectSetTimeField(dst, storageapi.DefaultCreatedAtField, now)
   120→		reflectSetTimeField(dst, storageapi.DefaultUpdatedAtField, now)
   121→		doc = dst.Elem().Interface()
   122→	}
   123→	return doc
   124→}
