   126→// Encode encodes doc into a reversible format (via Decode)
   127→// and returns the data in bytes.
   128→func Encode(m docmarshal.Marshaler, doc any, addCreatedAt bool) []byte {
   129→	if addCreatedAt {
   130→		doc = UpdateCreatedAtField(m, doc)
   131→	} else {
   132→		doc = UpdateUpdatedAtField(m, doc)
   133→	}
   134→
   135→	b, err := m.Marshal(doc)
   136→	if err != nil {
   137→		panic(err)
   138→	}
   139→	return b
   140→}
   141→
   142→// SafeDecode checks if the given interface would be decoded by Decode
   143→// and decodes it or otherwise returns an error.
   144→func SafeDecode(m docmarshal.Marshaler, rcv any, raw []byte) error {
   145→	if !IsEncodeable(rcv) {
   146→		return errors.New("receiver is not a pointer and not a map or is nil")
   147→	}
   148→	return decode(m, rcv, raw)
   149→}
   150→
   151→// IsEncodeable returns true if doc is a structure that can be safely
   152→// decoded via Decode.
   153→func IsEncodeable(doc any) bool {
   154→	v := reflect.ValueOf(doc)
   155→	return (v.Kind() == reflect.Ptr || v.Kind() == reflect.Map) && !v.IsNil()
   156→}
   157→
   158→// ListIterator returns an iterator that iterates over docs.
   159→// It will uson bson to encode and decode the data so
   160→// it shouldn't be used by a document.Service that doesn't use
   161→// the suite of Decode/Encode functions in this package.
   162→func NewListIterator(m docmarshal.Marshaler, docs ...any) *ListIterator {
   163→	iter := &ListIterator{marshaler: m, docs: make([][]byte, 0)}
   164→	for _, data := range docs {
   165→		iter.Extend(nil, Encode(m, data, false))
   166→	}
   167→	return iter
   168→}
   169→
   170→// ListIterator satisfies an Iterator with an inmemory
   171→// list of documents.
   172→type ListIterator struct {
   173→	marshaler docmarshal.Marshaler
   174→	docs      [][]byte
   175→}
   176→
   177→// HasNext returns false if this Iterator is empty.
   178→func (l *ListIterator) HasNext() bool {
   179→	return len(l.docs) > 0
   180→}
   181→
   182→// NextTo decodes the next chunk of data into doc or returns
   183→// an error if there was a decoding issue.
   184→func (l *ListIterator) NextTo(doc any) error {
   185→	if err := SafeDecode(l.marshaler, doc, l.docs[0]); err != nil {
   186→		return err
   187→	}
   188→	l.docs = l.docs[1:]
   189→	return nil
   190→}
   191→
   192→// Close does nothing.
   193→func (l *ListIterator) Close() error {
   194→	return nil
   195→}
   196→
   197→// Extend extends this iterator if and only if the data chunk's
   198→// structure satisfies all filters.
   199→func (l *ListIterator) Extend(filters []storageapi.Filter, v []byte) {
   200→	var proto map[string]any
   201→	// if bogus data is inserted into the DB oob,
   202→	// then we ignore it here, rather than failing a list operation
   203→	err := decode(l.marshaler, &proto, v)
   204→	if err != nil {
   205→		slog.Warn("failed to add value to iterator: decode", "error", err)
   206→		return
   207→	}
   208→	if !MatchesAllFilters(l.marshaler, proto, filters) {
   209→		return
   210→	}
   211→
   212→	copied := make([]byte, len(v))
   213→	copy(copied, v)
   214→	l.docs = append(l.docs, copied)
   215→}
   216→
   217→// UpdateProto updates proto with the given slice of updates.
   218→func UpdateProto(m docmarshal.Marshaler, updates []storageapi.Update,
   219→	proto map[string]any, preconds ...storageapi.Precondition) error {
   220→	lowerCase := m.DefaultLowerCase()
   221→
   222→	updatedAtField := storageapi.DefaultUpdatedAtField
   223→	if lowerCase {
   224→		updatedAtField = storageapi.LowerUpdatedAtField
   225→	}
   226→
   227→	for _, cond := range preconds {
   228→		if len(cond.FieldPath) == 0 {
   229→			panic("empty field path")
   230→		}
   231→
   232→		fieldPath := cond.FieldPath
   233→		if lowerCase {
   234→			fieldPath = make([]string, len(cond.FieldPath))
   235→			for i, comp := range cond.FieldPath {
   236→				fieldPath[i] = strings.ToLower(comp)
   237→			}
   238→		}
   239→
   240→		if !precondField(proto, storageapi.Precondition{FieldPath: fieldPath, Value: cond.Value}) {
   241→			return storageapi.ErrPreconditionFailed
   242→		}
   243→	}
   244→
   245→	for _, update := range updates {
   246→		if len(update.FieldPath) == 0 {
   247→			panic("empty field path")
   248→		}
   249→		if update.FieldPath[0] == updatedAtField {
   250→			continue
   251→		}
   252→
   253→		fieldPath := update.FieldPath
   254→		if lowerCase {
   255→			fieldPath = make([]string, len(update.FieldPath))
   256→			for i, comp := range update.FieldPath {
   257→				fieldPath[i] = strings.ToLower(comp)
   258→			}
   259→		}
   260→
   261→		updateField(proto, storageapi.Update{FieldPath: fieldPath, Value: update.Value})
   262→	}
   263→
   264→	updateField(proto, storageapi.Update{
   265→		FieldPath: []string{updatedAtField},
   266→		Value:     time.Now(),
   267→	})
   268→
   269→	return nil
   270→}
