   272→// DerefCreateValue dereferences data for a service.Create implementation
   273→// until it finds a structure that can be used for Encode/Decode
   274→// or returns an error if no such structure could be found.
   275→func DerefCreateValue(data reflect.Value) (any, error) {
   276→	for {
   277→		switch data.Kind() {
   278→		case reflect.Struct, reflect.Map:
   279→			return data.Interface(), nil
   280→		case reflect.Ptr:
   281→			data = data.Elem()
   282→		case reflect.Interface:
   283→			if data.NumMethod() == 0 {
   284→				data = data.Elem()
   285→				continue
   286→			}
   287→			fallthrough
   288→		default:
   289→			return nil, errors.New("only struct or map values are allowed")
   290→		}
   291→	}
   292→}
   293→
   294→func reflectSetTimeField(s reflect.Value, k string, v time.Time) {
   295→	f := s.Elem().FieldByName(k)
   296→	if !f.IsValid() || !f.CanSet() || f.Kind() != reflect.Struct ||
   297→		reflect.TypeOf(f) == reflect.TypeOf((*time.Time)(nil)).Elem() {
   298→		return
   299→	}
   300→	f.Set(reflect.ValueOf(v))
   301→}
   302→
   303→func cloneReflectValue(data any) reflect.Value {
   304→	typ := reflect.TypeOf(data)
   305→	src := reflect.ValueOf(data)
   306→	dst := reflect.New(typ)
   307→	for i := 0; i < src.NumField(); i++ {
   308→		dstField := dst.Elem().Field(i)
   309→		if dstField.CanSet() {
   310→			dstField.Set(src.Field(i))
   311→		}
   312→	}
   313→	return dst
   314→}
   315→
   316→func setMapField(m map[string]any, key string, value any) map[string]any {
   317→	ret := make(map[string]any)
   318→	for k, v := range m {
   319→		ret[k] = v
   320→	}
   321→	ret[key] = value
   322→	return ret
   323→}
   324→
   325→func precondField(proto map[string]any, cond storageapi.Precondition) bool {
   326→	if len(cond.FieldPath) == 1 {
   327→		return proto[cond.FieldPath[0]] == cond.Value
   328→	}
   329→
   330→	field, exist := proto[cond.FieldPath[0]]
   331→	if !exist {
   332→		return false
   333→	}
   334→
   335→	m, ok := field.(map[string]any)
   336→	if !ok {
   337→		return false
   338→	}
   339→
   340→	cond.FieldPath = cond.FieldPath[1:]
   341→	return precondField(m, cond)
   342→}
   343→
   344→func updateField(proto map[string]any, update storageapi.Update) {
   345→	if len(update.FieldPath) == 1 {
   346→		proto[update.FieldPath[0]] = update.Value
   347→		return
   348→	}
   349→
   350→	field, exist := proto[update.FieldPath[0]]
   351→	if !exist {
   352→		// surprisingly, FireStore does not return an error and also
   353→		// it doesn't add the extra fields. Since we are emulating
   354→		// the same behaviour, just return silently instead of
   355→		// creating the attribute path.
   356→		return
   357→	}
   358→
   359→	m, ok := field.(map[string]any)
   360→	if !ok {
   361→		return
   362→	}
   363→
   364→	update.FieldPath = update.FieldPath[1:]
   365→	updateField(m, update)
   366→}
   367→
   368→type filterAsserter struct {
   369→	res *bool
   370→}
   371→
   372→func (f *filterAsserter) Errorf(_ string, _ ...any) {
   373→	*f.res = false
   374→}
   375→
   376→func doMatchFilter(value any, f storageapi.Filter) bool {
   377→	matches := true
   378→	t := filterAsserter{res: &matches}
   379→
   380→	switch f.Op {
   381→	case storageapi.OpEqual:
   382→		assert.EqualValues(&t, value, f.Value)
   383→	case storageapi.OpGreaterThan:
   384→		assert.Greater(&t, value, f.Value)
   385→	case storageapi.OpLessThan:
   386→		assert.Less(&t, value, f.Value)
   387→	case storageapi.OpGreaterThanEqual:
   388→		assert.EqualValues(&t, value, f.Value)
   389→		if !matches {
   390→			matches = true
   391→			assert.GreaterOrEqual(&t, value, f.Value)
   392→		}
   393→	case storageapi.OpLessThanEqual:
   394→		assert.EqualValues(&t, value, f.Value)
   395→		if !matches {
   396→			matches = true
   397→			assert.LessOrEqual(&t, value, f.Value)
   398→		}
   399→	default:
   400→		panic("unexpected op")
   401→	}
   402→
   403→	return matches
   404→}
   405→
   406→// MatchFilter returns true if proto satisfies the filter condition of f.
   407→func MatchFilter(proto map[string]any, f storageapi.Filter) bool {
   408→	if len(f.FieldPath) == 1 {
   409→		return doMatchFilter(proto[f.FieldPath[0]], f)
   410→	}
   411→
   412→	field, exist := proto[f.FieldPath[0]]
   413→	if !exist || field == nil {
   414→		return false
   415→	}
   416→
   417→	m := field.(map[string]any)
   418→	f.FieldPath = f.FieldPath[1:]
   419→	return MatchFilter(m, f)
   420→}
   421→
   422→// MatchesAllFilters returns true if proto satisfies all of the give filters.
   423→func MatchesAllFilters(
   424→	m docmarshal.Marshaler, proto map[string]any,
   425→	filters []storageapi.Filter,
   426→) bool {
   427→	for _, f := range filters {
   428→		if m.DefaultLowerCase() {
   429→			fieldPath := make([]string, len(f.FieldPath))
   430→			for i, comp := range f.FieldPath {
   431→				fieldPath[i] = strings.ToLower(comp)
   432→			}
   433→			f.FieldPath = fieldPath
   434→		}
   435→
   436→		if !MatchFilter(proto, f) {
   437→			return false
   438→		}
   439→	}
   440→	return true
   441→}
   442→
   443→func decode(m docmarshal.Marshaler, rcv any, raw []byte) error {
   444→	return m.Unmarshal(raw, rcv)
   445→}
