// Setup - with proper cleanup and lifecycle management
func newE2EEnv(t *testing.T) *e2eEnv {
    t.Helper()

    // 1. Find external binary with fallback paths
    goplsBin, err := exec.LookPath("gopls")
    if err != nil {
        for _, p := range []string{
            filepath.Join(os.Getenv("HOME"), ".rune", "bin", "gopls"),
            filepath.Join(os.Getenv("HOME"), "go", "bin", "gopls"),
        } {
            if _, err := os.Stat(p); err == nil {
                goplsBin = p
                break
            }
        }
        if goplsBin == "" {
            t.Skip("gopls not found, skipping e2e tests")
        }
    }

    // 2. Prepare test data in temp directory
    tmpDir := t.TempDir()
    testdataDir := filepath.Join("testdata")
    entries, err := os.ReadDir(testdataDir)
    for _, e := range entries {
        src := filepath.Join(testdataDir, e.Name())
        dst := filepath.Join(tmpDir, e.Name())
        data, err := os.ReadFile(src)
        require.NoError(t, os.WriteFile(dst, data, 0644))
    }

    // 3. Start external process with cancellable context
    ctx, cancel := context.WithCancel(context.Background())
    cmd := exec.CommandContext(ctx, goplsBin, "serve")
    cmd.Dir = tmpDir
    stdinPipe, err := cmd.StdinPipe()
    stdoutPipe, err := cmd.StdoutPipe()
    require.NoError(t, cmd.Start())

    // 4. Set up communication protocol (JSON-RPC over pipes)
    conn := newRPCConn(stdinPipe, stdoutPipe)  // Manages bidirectional communication

    // 5. Set up gRPC server wrapping the external process
    srv := grpc.NewServer()
    semanticrpc.RegisterLSPServer(srv, semanticrpc.NewServer(adapter))
    go func() { _ = srv.Serve(lis) }()

    // 6. Create cleanup function (called via t.Cleanup)
    stop := func() {
        _ = client.Shutdown(context.Background())
        _ = client.Exit(context.Background())
        _ = cc.Close()
        srv.GracefulStop()
        cancel()
        _ = cmd.Wait()
    }

    return &e2eEnv{client: client, stop: stop}
}
