	"net"
	"os"
	"os/exec"
	"path/filepath"
	"strconv"
	"strings"
	"sync"
	"testing"
	"time"

	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
	"github.com/unstablebuild/rune-go-sdk/api/semanticapi"
	"github.com/unstablebuild/rune-go-sdk/api/semanticapi/semanticrpc"
	"google.golang.org/grpc"
	"google.golang.org/grpc/credentials/insecure"
)

func TestE2E(t *testing.T) {
	env := newE2EEnv(t)
	t.Cleanup(env.stop)
	ctx := context.Background()

	t.Run("Hover", func(t *testing.T) {
		result, err := env.client.Hover(ctx, semanticapi.HoverParams{
			TextDocument: semanticapi.TextDocumentIdentifier{URI: env.mainURI},
			Position:     semanticapi.Position{Line: 22, Character: 13},
		})
		require.NoError(t, err)
		require.NotNil(t, result, "expected hover result for Add")
		assert.Contains(t, result.Contents.Value, "Add")
	})

	t.Run("Hover on Greeter", func(t *testing.T) {
		result, err := env.client.Hover(ctx, semanticapi.HoverParams{
			TextDocument: semanticapi.TextDocumentIdentifier{URI: env.mainURI},
			Position:     semanticapi.Position{Line: 5, Character: 5},
		})
		require.NoError(t, err)
		require.NotNil(t, result)
		assert.Contains(t, result.Contents.Value, "Greeter")
	})

	t.Run("Hover nil on whitespace", func(t *testing.T) {
		result, err := env.client.Hover(ctx, semanticapi.HoverParams{
			TextDocument: semanticapi.TextDocumentIdentifier{URI: env.mainURI},
			Position:     semanticapi.Position{Line: 1, Character: 0},
		})
		require.NoError(t, err)
		assert.Nil(t, result)
	})

	t.Run("Definition of Add call", func(t *testing.T) {
		locs, err := env.client.Definition(ctx, semanticapi.DefinitionParams{
			TextDocument: semanticapi.TextDocumentIdentifier{URI: env.mainURI},
			Position:     semanticapi.Position{Line: 22, Character: 13},
		})
		require.NoError(t, err)
		require.NotEmpty(t, locs)
		assert.Equal(t, env.mainURI, locs[0].URI)
		assert.Equal(t, uint32(15), locs[0].Range.Start.Line)
	})

	t.Run("Definition of Greet call", func(t *testing.T) {
		locs, err := env.client.Definition(ctx, semanticapi.DefinitionParams{
			TextDocument: semanticapi.TextDocumentIdentifier{URI: env.mainURI},
			Position:     semanticapi.Position{Line: 21, Character: 15},
		})
		require.NoError(t, err)
		require.NotEmpty(t, locs)
		assert.Equal(t, env.mainURI, locs[0].URI)
		assert.Equal(t, uint32(10), locs[0].Range.Start.Line)
	})

	t.Run("References of Add", func(t *testing.T) {
		locs, err := env.client.References(ctx, semanticapi.ReferenceParams{
			TextDocument: semanticapi.TextDocumentIdentifier{URI: env.mainURI},
			Position:     semanticapi.Position{Line: 15, Character: 5},
			Context:      semanticapi.ReferenceContext{IncludeDeclaration: true},
		})
		require.NoError(t, err)
		require.GreaterOrEqual(t, len(locs), 2)
		lines := make([]uint32, len(locs))
		for i, l := range locs {
			lines[i] = l.Range.Start.Line
		}
		assert.Contains(t, lines, uint32(15))
		assert.Contains(t, lines, uint32(22))
	})

	t.Run("DocumentSymbol main.go", func(t *testing.T) {
		syms, err := env.client.DocumentSymbol(ctx, semanticapi.DocumentSymbolParams{
			TextDocument: semanticapi.TextDocumentIdentifier{URI: env.mainURI},
		})
		require.NoError(t, err)
		require.NotEmpty(t, syms)
		names := make([]string, len(syms))
		for i, s := range syms {
			names[i] = s.Name
		}
		assert.Contains(t, names, "Greeter")
		assert.Contains(t, names, "Add")
		assert.Contains(t, names, "main")
	})

	t.Run("DocumentSymbol util.go", func(t *testing.T) {
		syms, err := env.client.DocumentSymbol(ctx, semanticapi.DocumentSymbolParams{
			TextDocument: semanticapi.TextDocumentIdentifier{URI: env.utilURI},
		})
		require.NoError(t, err)
		names := make([]string, len(syms))
		for i, s := range syms {
			names[i] = s.Name
		}
		assert.Contains(t, names, "Multiply")
		assert.Contains(t, names, "Max")
	})

	t.Run("Completion", func(t *testing.T) {
		result, err := env.client.Completion(ctx, semanticapi.CompletionParams{
			TextDocument: semanticapi.TextDocumentIdentifier{URI: env.mainURI},
			Position:     semanticapi.Position{Line: 11, Character: 12},
		})
		require.NoError(t, err)
		require.NotEmpty(t, result.Items)
		labels := make([]string, len(result.Items))
		for i, item := range result.Items {
			labels[i] = item.Label
		}
		assert.Contains(t, labels, "Sprintf")
	})

	t.Run("Formatting", func(t *testing.T) {
		edits, err := env.client.Formatting(ctx, semanticapi.DocumentFormattingParams{
			TextDocument: semanticapi.TextDocumentIdentifier{URI: env.mainURI},
			Options:      semanticapi.FormattingOptions{TabSize: 4, InsertSpaces: false},
		})
		require.NoError(t, err)
		assert.Empty(t, edits)
	})

	t.Run("FoldingRange", func(t *testing.T) {
		ranges, err := env.client.FoldingRange(ctx, semanticapi.FoldingRangeParams{
			TextDocument: semanticapi.TextDocumentIdentifier{URI: env.mainURI},
		})
		require.NoError(t, err)
		require.NotEmpty(t, ranges)
		var hasFunc bool
		for _, r := range ranges {
			if r.StartLine >= 5 {
				hasFunc = true
				break
			}
		}
		assert.True(t, hasFunc, "expected folding ranges for function bodies")
	})

	t.Run("WorkspaceSymbol", func(t *testing.T) {
		syms, err := env.client.WorkspaceSymbol(ctx, semanticapi.WorkspaceSymbolParams{
			Query: "Greeter",
		})
		require.NoError(t, err)
		require.NotEmpty(t, syms)
		assert.Equal(t, "Greeter", syms[0].Name)
	})

	t.Run("WorkspaceSymbol Multiply", func(t *testing.T) {
		syms, err := env.client.WorkspaceSymbol(ctx, semanticapi.WorkspaceSymbolParams{
			Query: "Multiply",
		})
		require.NoError(t, err)
		require.NotEmpty(t, syms)
		assert.Equal(t, "Multiply", syms[0].Name)
	})

	t.Run("DocumentHighlight", func(t *testing.T) {
		highlights, err := env.client.DocumentHighlight(ctx, semanticapi.DocumentHighlightParams{
			TextDocument: semanticapi.TextDocumentIdentifier{URI: env.mainURI},
			Position:     semanticapi.Position{Line: 5, Character: 5},
		})
		require.NoError(t, err)
		require.NotEmpty(t, highlights)
	})

	t.Run("PrepareRename", func(t *testing.T) {
		result, err := env.client.PrepareRename(ctx, semanticapi.PrepareRenameParams{
			TextDocument: semanticapi.TextDocumentIdentifier{URI: env.mainURI},
			Position:     semanticapi.Position{Line: 15, Character: 5},
		})
		require.NoError(t, err)
		require.NotNil(t, result)
		assert.Equal(t, "Add", result.Placeholder)
		assert.Equal(t, uint32(15), result.Range.Start.Line)
	})

	t.Run("Rename", func(t *testing.T) {
		edit, err := env.client.Rename(ctx, semanticapi.RenameParams{
			TextDocument: semanticapi.TextDocumentIdentifier{URI: env.utilURI},
			Position:     semanticapi.Position{Line: 3, Character: 5},
			NewName:      "Mul",
		})
		require.NoError(t, err)
		require.NotNil(t, edit)
		require.NotEmpty(t, edit.Changes)
		edits, ok := edit.Changes[env.utilURI]
		require.True(t, ok, "expected edits in util.go")
		require.NotEmpty(t, edits)
		var foundNewName bool
		for _, e := range edits {
			if e.NewText == "Mul" {
				foundNewName = true
				break
			}
		}
		assert.True(t, foundNewName, "expected rename edit with NewText=Mul")
	})

	t.Run("SelectionRange", func(t *testing.T) {
		ranges, err := env.client.SelectionRange(ctx, semanticapi.SelectionRangeParams{
			TextDocument: semanticapi.TextDocumentIdentifier{URI: env.mainURI},
			Positions:    []semanticapi.Position{{Line: 16, Character: 1}},
		})
		require.NoError(t, err)
		require.Len(t, ranges, 1)
		assert.NotNil(t, ranges[0].Parent, "expected parent selection range")
	})

	t.Run("SemanticTokensFull", func(t *testing.T) {
		tokens, err := env.client.SemanticTokensFull(ctx, semanticapi.SemanticTokensParams{
			TextDocument: semanticapi.TextDocumentIdentifier{URI: env.mainURI},
		})
		require.NoError(t, err)
		require.NotNil(t, tokens)
		if len(tokens.Data) > 0 {
			assert.Equal(t, 0, len(tokens.Data)%5, "semantic token data should be a multiple of 5")
		}
	})

	t.Run("SemanticTokensRange", func(t *testing.T) {
		tokens, err := env.client.SemanticTokensRange(ctx, semanticapi.SemanticTokensRangeParams{
			TextDocument: semanticapi.TextDocumentIdentifier{URI: env.mainURI},
			Range: semanticapi.Range{
				Start: semanticapi.Position{Line: 0, Character: 0},
				End:   semanticapi.Position{Line: 10, Character: 0},
			},
		})
		require.NoError(t, err)
		require.NotNil(t, tokens)
	})

	t.Run("PrepareCallHierarchy", func(t *testing.T) {
		// PrepareCallHierarchy on "Add" at line 15, char 5.
		items, err := env.client.PrepareCallHierarchy(ctx, semanticapi.CallHierarchyPrepareParams{
			TextDocument: semanticapi.TextDocumentIdentifier{URI: env.mainURI},
			Position:     semanticapi.Position{Line: 15, Character: 5},
		})
		require.NoError(t, err)
		require.NotEmpty(t, items)
		assert.Equal(t, "Add", items[0].Name)
		assert.Equal(t, semanticapi.SymbolKindFunction, items[0].Kind)
	})

	t.Run("CallHierarchyIncomingCalls", func(t *testing.T) {
		// First prepare, then get incoming calls.
		items, err := env.client.PrepareCallHierarchy(ctx, semanticapi.CallHierarchyPrepareParams{
			TextDocument: semanticapi.TextDocumentIdentifier{URI: env.mainURI},
			Position:     semanticapi.Position{Line: 15, Character: 5},
		})
		require.NoError(t, err)
		require.NotEmpty(t, items)

		calls, err := env.client.CallHierarchyIncomingCalls(ctx, semanticapi.CallHierarchyIncomingCallsParams{
			Item: items[0],
		})
		require.NoError(t, err)
		require.NotEmpty(t, calls, "Add should have incoming calls from main")
		assert.Equal(t, "main", calls[0].From.Name)
	})

	t.Run("CallHierarchyOutgoingCalls", func(t *testing.T) {
		items, err := env.client.PrepareCallHierarchy(ctx, semanticapi.CallHierarchyPrepareParams{
			TextDocument: semanticapi.TextDocumentIdentifier{URI: env.mainURI},
			Position:     semanticapi.Position{Line: 19, Character: 5},
		})
		require.NoError(t, err)
		require.NotEmpty(t, items)

		calls, err := env.client.CallHierarchyOutgoingCalls(ctx, semanticapi.CallHierarchyOutgoingCallsParams{
			Item: items[0],
		})
		require.NoError(t, err)
		require.NotEmpty(t, calls, "main should have outgoing calls")
		outNames := make([]string, len(calls))
		for i, c := range calls {
			outNames[i] = c.To.Name
		}
		assert.Contains(t, outNames, "Add")
	})

	t.Run("CodeAction", func(t *testing.T) {
		actions, err := env.client.CodeAction(ctx, semanticapi.CodeActionParams{
			TextDocument: semanticapi.TextDocumentIdentifier{URI: env.mainURI},
			Range: semanticapi.Range{
				Start: semanticapi.Position{Line: 0, Character: 0},
				End:   semanticapi.Position{Line: 24, Character: 0},
			},
		})
		require.NoError(t, err)
		require.NotEmpty(t, actions)
	})

	t.Run("TypeDefinition", func(t *testing.T) {
		locs, err := env.client.TypeDefinition(ctx, semanticapi.TypeDefinitionParams{
			TextDocument: semanticapi.TextDocumentIdentifier{URI: env.mainURI},
			Position:     semanticapi.Position{Line: 20, Character: 1},
		})
		require.NoError(t, err)
		require.NotEmpty(t, locs)
		assert.Equal(t, env.mainURI, locs[0].URI)
		assert.Equal(t, uint32(5), locs[0].Range.Start.Line)
	})
}

type jsonrpcMessage struct {
	JSONRPC string          `json:"jsonrpc"`
	ID      *int            `json:"id,omitempty"`
	Method  string          `json:"method,omitempty"`
	Params  json.RawMessage `json:"params,omitempty"`
	Result  json.RawMessage `json:"result,omitempty"`
	Error   *jsonrpcError   `json:"error,omitempty"`
}

type jsonrpcError struct {
	Code    int    `json:"code"`
	Message string `json:"message"`
}

type rpcConn struct {
	mu      sync.Mutex
	nextID  int
	stdin   io.WriteCloser
	pending map[int]chan jsonrpcMessage
	closed  chan struct{}
	readErr error
}

func newRPCConn(stdin io.WriteCloser, stdout io.ReadCloser) *rpcConn {
	c := &rpcConn{
		stdin:   stdin,
		pending: make(map[int]chan jsonrpcMessage),
		closed:  make(chan struct{}),
	}
	go c.readLoop(stdout)
	return c
}

func (c *rpcConn) readLoop(r io.Reader) {
	br := bufio.NewReader(r)
	for {
		var contentLen int
		for {
			line, err := br.ReadString('\n')
			if err != nil {
				c.mu.Lock()
				c.readErr = err
				for _, ch := range c.pending {
					close(ch)
				}
				c.mu.Unlock()
				close(c.closed)
				return
			}
			line = strings.TrimSpace(line)
			if line == "" {
				break
			}
			if strings.HasPrefix(line, "Content-Length:") {
				val := strings.TrimSpace(strings.TrimPrefix(line, "Content-Length:"))
				contentLen, _ = strconv.Atoi(val)
			}
		}
		if contentLen == 0 {
			continue
		}

		body := make([]byte, contentLen)
		if _, err := io.ReadFull(br, body); err != nil {
			c.mu.Lock()
			c.readErr = err
			for _, ch := range c.pending {
				close(ch)
			}
			c.mu.Unlock()
			close(c.closed)
			return
		}

		var msg jsonrpcMessage
		if err := json.Unmarshal(body, &msg); err != nil {
			continue
		}

		if msg.ID != nil && msg.Method == "" {
			c.mu.Lock()
			ch, ok := c.pending[*msg.ID]
			if ok {
				delete(c.pending, *msg.ID)
			}
			c.mu.Unlock()
			if ok {
				ch <- msg
			}
		}
	}
}

func (c *rpcConn) call(ctx context.Context, method string, params, result any) error {
	c.mu.Lock()
	id := c.nextID
	c.nextID++
	ch := make(chan jsonrpcMessage, 1)
	c.pending[id] = ch
	c.mu.Unlock()

	paramBytes, err := json.Marshal(params)
	if err != nil {
		return err
	}
	req := jsonrpcMessage{
		JSONRPC: "2.0",
		ID:      &id,
		Method:  method,
		Params:  paramBytes,
	}
	body, err := json.Marshal(req)
	if err != nil {
		return err
	}
	header := fmt.Sprintf("Content-Length: %d\r\n\r\n", len(body))

	c.mu.Lock()
	_, err = io.WriteString(c.stdin, header)
	if err == nil {
		_, err = c.stdin.Write(body)
	}
	c.mu.Unlock()
	if err != nil {
		return err
	}

	select {
	case <-ctx.Done():
		return ctx.Err()
	case msg, ok := <-ch:
		if !ok {
			return fmt.Errorf("connection closed: %v", c.readErr)
		}
		if msg.Error != nil {
			return fmt.Errorf("rpc error %d: %s", msg.Error.Code, msg.Error.Message)
		}
		if result != nil && msg.Result != nil {
			return json.Unmarshal(msg.Result, result)
		}
		return nil
	}
}

func (c *rpcConn) notify(ctx context.Context, method string, params any) error {
	paramBytes, err := json.Marshal(params)
	if err != nil {
		return err
	}
	req := jsonrpcMessage{
		JSONRPC: "2.0",
		Method:  method,
		Params:  paramBytes,
	}
	body, err := json.Marshal(req)
	if err != nil {
		return err
	}
	header := fmt.Sprintf("Content-Length: %d\r\n\r\n", len(body))

	c.mu.Lock()
	defer c.mu.Unlock()
	if _, err := io.WriteString(c.stdin, header); err != nil {
		return err
	}
	_, err = c.stdin.Write(body)
	return err
}

