type e2eEnv struct {
	client  semanticapi.LSP
	mainURI string
	utilURI string
	stop    func()
}

func newE2EEnv(t *testing.T) *e2eEnv {
	t.Helper()

	goplsBin, err := exec.LookPath("gopls")
	if err != nil {
		for _, p := range []string{
			filepath.Join(os.Getenv("HOME"), ".rune", "bin", "gopls"),
			filepath.Join(os.Getenv("HOME"), "go", "bin", "gopls"),
		} {
			if _, err := os.Stat(p); err == nil {
				goplsBin = p
				break
			}
		}
		if goplsBin == "" {
			t.Skip("gopls not found, skipping e2e tests")
		}
	}

	tmpDir := t.TempDir()
	testdataDir := filepath.Join("testdata")
	entries, err := os.ReadDir(testdataDir)
	require.NoError(t, err)
	for _, e := range entries {
		src := filepath.Join(testdataDir, e.Name())
		dst := filepath.Join(tmpDir, e.Name())
		data, err := os.ReadFile(src)
		require.NoError(t, err)
		require.NoError(t, os.WriteFile(dst, data, 0644))
	}

	ctx, cancel := context.WithCancel(context.Background())
	cmd := exec.CommandContext(ctx, goplsBin, "serve")
	cmd.Dir = tmpDir
	stdinPipe, err := cmd.StdinPipe()
	require.NoError(t, err)
	stdoutPipe, err := cmd.StdoutPipe()
	require.NoError(t, err)
	require.NoError(t, cmd.Start())

	conn := newRPCConn(stdinPipe, stdoutPipe)
	adapter := &goplsLSP{conn: conn}

	n := sockCounter.Add(1)
	sock := filepath.Join(os.TempDir(), fmt.Sprintf("lsp_e2e_%d_%d.sock", os.Getpid(), n))
	t.Cleanup(func() { _ = os.Remove(sock) })
	lis, err := net.Listen("unix", sock)
	require.NoError(t, err)

	srv := grpc.NewServer()
	semanticrpc.RegisterLSPServer(srv, semanticrpc.NewServer(adapter))
	go func() { _ = srv.Serve(lis) }()

	cc, err := grpc.NewClient(
		"passthrough:///unix://"+sock,
		grpc.WithTransportCredentials(insecure.NewCredentials()),
		grpc.WithContextDialer(func(ctx context.Context, addr string) (net.Conn, error) {
			var d net.Dialer
			return d.DialContext(ctx, "unix", sock)
		}),
	)
	require.NoError(t, err)

	client := semanticrpc.NewClient(context.Background(), cc)

	rootURI := "file://" + tmpDir
	mainURI := "file://" + filepath.Join(tmpDir, "main.go")
	utilURI := "file://" + filepath.Join(tmpDir, "util.go")

	_, err = client.Initialize(ctx, semanticapi.InitializeParams{RootURI: rootURI})
	require.NoError(t, err)
	require.NoError(t, client.Initialized(ctx))

	mainContent, err := os.ReadFile(filepath.Join(tmpDir, "main.go"))
	require.NoError(t, err)
	utilContent, err := os.ReadFile(filepath.Join(tmpDir, "util.go"))
	require.NoError(t, err)

	require.NoError(t, client.DidOpen(ctx, semanticapi.DidOpenTextDocumentParams{
		TextDocument: semanticapi.TextDocumentItem{
			URI: mainURI, LanguageID: "go", Version: 1, Text: string(mainContent),
		},
	}))
	require.NoError(t, client.DidOpen(ctx, semanticapi.DidOpenTextDocumentParams{
		TextDocument: semanticapi.TextDocumentItem{
			URI: utilURI, LanguageID: "go", Version: 1, Text: string(utilContent),
		},
	}))

	time.Sleep(3 * time.Second)

	stop := func() {
		_ = client.Shutdown(context.Background())
		_ = client.Exit(context.Background())
		_ = cc.Close()
		srv.GracefulStop()
		cancel()
		_ = cmd.Wait()
	}

	return &e2eEnv{
		client:  client,
		mainURI: mainURI,
		utilURI: utilURI,
		stop:    stop,
	}
}

