func (g *goplsLSP) CodeAction(ctx context.Context, params semanticapi.CodeActionParams) ([]semanticapi.CodeAction, error) {
	diags := make([]any, len(params.Context.Diagnostics))
	for i, d := range params.Context.Diagnostics {
		diags[i] = map[string]any{
			"range":    d.Range,
			"severity": int(d.Severity),
			"message":  d.Message,
		}
	}
	p := map[string]any{
		"textDocument": map[string]any{"uri": params.TextDocument.URI},
		"range":        params.Range,
		"context":      map[string]any{"diagnostics": diags},
	}
	var result []lspCodeAction
	if err := g.conn.call(ctx, "textDocument/codeAction", p, &result); err != nil {
		return nil, err
	}
	ret := make([]semanticapi.CodeAction, len(result))
	for i, a := range result {
		ret[i] = semanticapi.CodeAction{
			Title: a.Title,
			Kind:  semanticapi.CodeActionKind(a.Kind),
			Edit:  lspWorkspaceEditToSemantic(a.Edit),
		}
		if a.Command != nil {
			cmd := &semanticapi.Command{
				Title:   a.Command.Title,
				Command: a.Command.Command,
			}
			cmd.Arguments = append(cmd.Arguments, a.Command.Arguments...)
			ret[i].Command = cmd
		}
	}
	return ret, nil
}

